var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 이게 무슨 소리지?","JPN":"うん？　これは何の音？","ENG":"Mm... What's that noise?","TWN":"呃嗯，這是什麼聲音？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 학생 여러분.","JPN":"生徒の皆様、お待たせいたしました。","ENG":"Dear students, thank you for your patience.","TWN":"同學們，大家久等了。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조화와 화합의 학원제, 애쉬포드 학원제가 내일로 다가왔습니다. 모두 후회없는 축제 준비를 부탁드리겠습니다.","JPN":"いよいよ調和と和合の学園祭、アッシュフォード学園祭が明日へと迫りました。\\n皆さん、悔いのないように準備をお願いします。","ENG":"Tomorrow is the Harmony and Balance Festival at Ashford Academy. I hope everyone makes every effort to prepare for the festival.","TWN":"明天就是全校同歡的阿什弗德學園祭，請大家做足準備，不要留下遺憾。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장? 어제도 이거랑 비슷한 일이 있지 않았나?","JPN":"会長？　っていうか、昨日も同じようなことがあったような？","ENG":"Yen? Didn't she say something similar yesterday?","TWN":"會長？昨天不是也說過一樣的話嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"분명, 이 다음에 나이엘이…….","JPN":"確か、この後ナイエルが……","ENG":"And right after, Naielle says...","TWN":"接下來奈爾就會……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！\\n全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 지금 건? 전야제 준비 방송인가?","JPN":"なんだ、今の？　前夜祭の準備放送か？","ENG":"Huh? What was that? Was that the rehearsal broadcast for tomorrow's festival?","TWN":"剛那是怎樣？是在彩排嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 평소대로의 학생회 같은 분위기잖아? 내일 학원제가 기대되는 걸?","JPN":"ふふっ。でも、生徒会らしいじゃない。明日の学園祭が楽しみね。","ENG":"Well, it's just any other day for the Student Council. Anyway, I'm hyped about tomorrow's festival!","TWN":"不是學生會的日常發揮嗎？真期待明天的學園祭。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 대체 뭐가 어떻게 돌아가는 거야? 분명 어제도……","JPN":"いや、いったい何がどうなっているの？　確か昨日も……","ENG":"Wait a minute. What's going on? This all happened yesterday...","TWN":"等等，現在到底是什麼情況？明明昨天就……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어제? 가만, 어제 무슨 일이 있었더라?","JPN":"昨日？　ん？　昨日何かあったっけ？","ENG":"Yesterday? Huh? What happened yesterday?","TWN":"昨天？等等，昨天發生了什麼事？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"정말! 이런 곳에서 뭘 하고 있어! 다들 널 얼마나 찾았는데!","JPN":"もう！　こんなところで何してるの？　みんな探してたんだよ！","ENG":"Seriously? What are you doing here? Everyone's been looking all over for you!","TWN":"真是的！你在這裡做什麼！大家都在找你！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 너는? 그러니까, 셜리였던가?","JPN":"あ、あなたは？　えっと、シャーリーだったっけ？","ENG":"Huh? You're…? Uh, Shirley, right?","TWN":"喔！你是？你是夏麗嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"뭐어? 미나, 설마 내 이름 잊어버린 거야?","JPN":"ええっ？！　ミナ、まさか私の名前を忘れたの？","ENG":"Huh? Mina, did you forget my name?","TWN":"什麼？米娜，你忘記我的名字了嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아니 그런 건 아닌데 왠지 엄청 오랜만에 보는 것 같아서.","JPN":"いや、そういうわけじゃないけど、\\nなんだかとても久しぶりに会った気がしてね。","ENG":"N-no, it just felt like I haven't seen you in a long time.","TWN":"不，不是啦，我沒忘，只是有種好久不見的感覺。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"우리 어제도 봤잖아? 이상하네. 아니면 그새 보고 싶었던 거야?","JPN":"私たち昨日も会ったでしょ？\\n変なの。それとも、そんなに私に会いたかったのかな？","ENG":"But we saw each other yesterday. Strange. Or did you miss me that much?","TWN":"我們昨天不是也有見面嗎？你這麼快就想我啦？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으, 으응. 그런가…….","JPN":"う、うん。そうだね……","ENG":"Y-yeah... I think that's it...","TWN":"呃，嗯，是這樣嗎……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"기쁘긴 한데. 어쨌든 빨리 학생회실로 돌아가자. 이러다 회의 늦겠어.","JPN":"それは嬉しいけどさ。\\n今ははやく生徒会室に行こう。会議に遅れちゃうよ。","ENG":"I'm flattered, but we need to get to the Student Council office. We're gonna be late for the meeting.","TWN":"我是很開心啦，但我們還是先回去學生會辦公室吧，快遲到啦。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학생회실? 아아, 나는 학생회 임원이고…… 그래서 학원제 준비를……. 응?","JPN":"生徒会室？　ああ、私は生徒会役員だから……\\n学園祭の準備を進めなきゃ……、あれ？","ENG":"The Student Council office? Oh, I'm a Student Council member... and I need to help with the festival prep... hmm?","TWN":"學生會辦公室？喔喔～我是學生會幹部……要準備學園祭……嗯？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐! 셜리, 학원제는 오늘부터 시작이잖아?","JPN":"まって、シャーリー！　学園祭って今日からだよね？","ENG":"Wait! Shirley, doesn't the festival start today?","TWN":"夏麗，我問你，學園祭是今天開始吧？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야, 학원제는 내일부터 시작인 걸?","JPN":"何を言ってるの、学園祭は明日からだよ？","ENG":"What are you talking about? It starts tomorrow.","TWN":"你在說什麼？學園祭是明天開始。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};